def process_transactions(transactions):
    # Use a dictionary to store the account balances
    accounts = {}

    # Iterate over the transactions and update the account balances
    for transaction in transactions:
        # Get the account number and amount of the transaction
        account, amount = transaction

        # Check if the account is already in the dictionary
        if account not in accounts:
            # If the account is not in the dictionary, create a new entry with a starting balance of 0
            accounts[account] = 0

        # Update the account balance by adding or subtracting the amount of the transaction
        accounts[account] += amount

    return accounts